mapper.sql:
where deleted = 0
  and user_id = #{userId}
  and ifnull(user_code, '') = ifnull(#{userCode}, '')

    and (memory_title like concat('%', #{keyword}, '%')
         or memory_summary like concat('%', #{keyword}, '%'))


    and memory_type = #{memoryType}


    and status = #{status}

mapper.select:
select count(1)
from ai_user_memory
where deleted = 0
  and user_id = #{userId}
  and ifnull(user_code, '') = ifnull(#{userCode}, '')
  and memory_type = #{memoryType}
  and memory_summary = #{memorySummary}

select id from ai_user_memory
where deleted = 0
  and status = #{status}
  and (
      (last_reinforced_at is not null and last_reinforced_at < #{beforeTime})
      or
      (last_reinforced_at is null and created_at < #{beforeTime})
  )
order by coalesce(last_reinforced_at, created_at) asc
limit #{limit}

mapper.update:
update ai_user_memory
set deleted = 1, updated_at = current_timestamp
where id = #{id}
  and user_id = #{userId}
  and ifnull(user_code, '') = ifnull(#{userCode}, '')
